// AUTO-GENERATED by scripts/utils/sync-brand-static.js — do not edit
export const BRAND_STATIC_BUNDLE = {"docs.html":{"contentType":"text/html; charset=utf-8","body":"<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\" />\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n  <title>Brand API Documentation — Eazpire</title>\n  <link rel=\"icon\" href=\"/favicon.svg\" type=\"image/svg+xml\" />\n  <link rel=\"stylesheet\" href=\"/shared/css/brand-ui.css\" />\n  <style>\n    .docs-page {\n      max-width: 920px;\n      margin: 0 auto;\n      padding: 32px 20px 80px;\n    }\n    .docs-hero {\n      display: flex;\n      gap: 14px;\n      align-items: flex-start;\n      margin-bottom: 28px;\n    }\n    .docs-hero h1 { margin: 0 0 6px; font-size: 1.75rem; }\n    .docs-hero p { margin: 0; color: var(--muted); }\n    .docs-nav {\n      display: flex;\n      flex-wrap: wrap;\n      gap: 8px;\n      margin-bottom: 28px;\n    }\n    .docs-nav a {\n      text-decoration: none;\n      color: var(--brand);\n      background: rgba(15, 118, 110, 0.08);\n      padding: 6px 12px;\n      border-radius: 999px;\n      font-size: 0.85rem;\n      font-weight: 600;\n    }\n    .docs-section {\n      background: var(--surface);\n      border: 1px solid var(--line);\n      border-radius: var(--radius);\n      padding: 20px 22px;\n      margin-bottom: 16px;\n      box-shadow: var(--shadow-sm);\n    }\n    .docs-section h2 {\n      margin: 0 0 10px;\n      font-size: 1.15rem;\n    }\n    .docs-section h3 {\n      margin: 18px 0 8px;\n      font-size: 0.95rem;\n    }\n    .docs-section p, .docs-section li { color: var(--text); line-height: 1.55; }\n    .docs-section .muted { color: var(--muted); }\n    table.docs-table {\n      width: 100%;\n      border-collapse: collapse;\n      font-size: 0.9rem;\n    }\n    table.docs-table th,\n    table.docs-table td {\n      text-align: left;\n      padding: 8px 10px;\n      border-bottom: 1px solid var(--line);\n      vertical-align: top;\n    }\n    table.docs-table th { color: var(--muted); font-weight: 600; }\n    code, .code-inline {\n      font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;\n      font-size: 0.84em;\n      background: var(--surface-3);\n      padding: 1px 6px;\n      border-radius: 6px;\n    }\n    pre.docs-code {\n      margin: 10px 0 0;\n      padding: 14px 16px;\n      background: #0b1420;\n      color: #e2e8f0;\n      border-radius: 12px;\n      overflow: auto;\n      font-size: 0.82rem;\n      line-height: 1.45;\n    }\n    .method {\n      display: inline-block;\n      min-width: 3.2rem;\n      font-weight: 700;\n      font-size: 0.75rem;\n      color: var(--brand);\n    }\n    .badge-soon {\n      display: inline-block;\n      font-size: 0.7rem;\n      font-weight: 700;\n      text-transform: uppercase;\n      letter-spacing: 0.04em;\n      background: rgba(245, 158, 11, 0.15);\n      color: #b45309;\n      padding: 2px 8px;\n      border-radius: 999px;\n      margin-left: 6px;\n    }\n    .docs-footer {\n      margin-top: 24px;\n      color: var(--muted);\n      font-size: 0.9rem;\n    }\n  </style>\n</head>\n<body>\n  <div class=\"docs-page\">\n    <div class=\"docs-hero\">\n      <div class=\"logo-mark\">EB</div>\n      <div>\n        <h1>Brand API Documentation</h1>\n        <p>Machine access to your brand on <strong>brand.eazpire.com</strong> — catalog, dual-publish, team, and profile.</p>\n      </div>\n    </div>\n\n    <div class=\"docs-nav\">\n      <a href=\"#auth\">Authentication</a>\n      <a href=\"#scopes\">Scopes</a>\n      <a href=\"#endpoints\">Endpoints</a>\n      <a href=\"#errors\">Errors</a>\n      <a href=\"#examples\">Examples</a>\n      <a href=\"/settings\">Portal Settings</a>\n    </div>\n\n    <section class=\"docs-section\" id=\"auth\">\n      <h2>Authentication</h2>\n      <p>Create an <strong>eazpire API key</strong> in the Brand Portal under <a href=\"/settings\">Settings → eazpire API keys</a>. The full key is shown <strong>once</strong>.</p>\n      <p>Send the key on every request:</p>\n      <ul>\n        <li><code>Authorization: Bearer eaz_brand_…</code></li>\n        <li>or <code>X-Eazpire-Brand-Key: eaz_brand_…</code></li>\n      </ul>\n      <p class=\"muted\">Portal browser sessions use a cookie instead and have full access (<code>*</code>). Keys are scoped to one brand and never store the raw secret after creation.</p>\n      <p class=\"muted\"><strong>Not the same as:</strong> BYO Printify/Shopify connections, or “Link eazpire Account” (Customer Account OAuth for Creator design).</p>\n    </section>\n\n    <section class=\"docs-section\" id=\"scopes\">\n      <h2>Scopes</h2>\n      <p>When creating a key you can pick scopes, or leave defaults (all listed scopes). Use <code>*</code> for full access.</p>\n      <table class=\"docs-table\">\n        <thead>\n          <tr><th>Scope</th><th>Allows</th></tr>\n        </thead>\n        <tbody>\n          <tr><td><code>overview:read</code></td><td>Brand overview + stats</td></tr>\n          <tr><td><code>brand:read</code></td><td>Read brand profile</td></tr>\n          <tr><td><code>brand:write</code></td><td>Update name, tagline, about, handle (no delete)</td></tr>\n          <tr><td><code>connections:read</code></td><td>Connection status (no secrets)</td></tr>\n          <tr><td><code>products:read</code></td><td>List / get products</td></tr>\n          <tr><td><code>products:write</code></td><td>Update local product title/status</td></tr>\n          <tr><td><code>products:sync</code></td><td>Sync catalog from BYO Printify</td></tr>\n          <tr><td><code>products:publish</code></td><td>Publish / unpublish on eazpire</td></tr>\n          <tr><td><code>team:read</code></td><td>List team members</td></tr>\n          <tr><td><code>team:invite</code></td><td>Invite creators by email</td></tr>\n          <tr><td><code>team:write</code></td><td>Update publish_mode / revoke members</td></tr>\n          <tr><td><code>*</code></td><td>All scopes</td></tr>\n        </tbody>\n      </table>\n    </section>\n\n    <section class=\"docs-section\" id=\"endpoints\">\n      <h2>Endpoints</h2>\n      <p class=\"muted\">Base URL: <code>https://brand.eazpire.com</code>. Prefer versioned paths; <code>?op=</code> aliases still work.</p>\n\n      <h3>Overview &amp; brand</h3>\n      <table class=\"docs-table\">\n        <thead><tr><th>Method / path</th><th>Scope</th><th>Notes</th></tr></thead>\n        <tbody>\n          <tr>\n            <td><span class=\"method\">GET</span> <code>/api/v1/overview</code></td>\n            <td><code>overview:read</code></td>\n            <td>Profile + product/member counts + connection summary</td>\n          </tr>\n          <tr>\n            <td><span class=\"method\">GET</span> <code>/api/v1/brand</code></td>\n            <td><code>brand:read</code></td>\n            <td>Brand profile only</td>\n          </tr>\n          <tr>\n            <td><span class=\"method\">POST</span> <code>/api/v1/brand</code></td>\n            <td><code>brand:write</code></td>\n            <td>Body: <code>{ name?, handle?, tagline?, about? }</code></td>\n          </tr>\n        </tbody>\n      </table>\n\n      <h3>Connections</h3>\n      <table class=\"docs-table\">\n        <thead><tr><th>Method / path</th><th>Scope</th><th>Notes</th></tr></thead>\n        <tbody>\n          <tr>\n            <td><span class=\"method\">GET</span> <code>/api/v1/connections</code></td>\n            <td><code>connections:read</code></td>\n            <td>Status, shop ids/names — never API secrets</td>\n          </tr>\n        </tbody>\n      </table>\n\n      <h3>Products</h3>\n      <table class=\"docs-table\">\n        <thead><tr><th>Method / path</th><th>Scope</th><th>Notes</th></tr></thead>\n        <tbody>\n          <tr>\n            <td><span class=\"method\">GET</span> <code>/api/v1/products</code></td>\n            <td><code>products:read</code></td>\n            <td>Optional <code>?status=active|draft</code></td>\n          </tr>\n          <tr>\n            <td><span class=\"method\">GET</span> <code>/api/v1/products/{id}</code></td>\n            <td><code>products:read</code></td>\n            <td>Single catalog row</td>\n          </tr>\n          <tr>\n            <td><span class=\"method\">POST</span> <code>/api/v1/products/{id}</code></td>\n            <td><code>products:write</code></td>\n            <td>Body: <code>{ title?, status? }</code> — local metadata only; Printify sync may overwrite</td>\n          </tr>\n          <tr>\n            <td><span class=\"method\">POST</span> <code>/api/v1/products/sync</code></td>\n            <td><code>products:sync</code></td>\n            <td>Refresh from BYO Printify</td>\n          </tr>\n          <tr>\n            <td><span class=\"method\">POST</span> <code>/api/v1/products/publish</code></td>\n            <td><code>products:publish</code></td>\n            <td><code>{ product_id }</code> or <code>{ product_ids }</code> or <code>{ limit }</code></td>\n          </tr>\n          <tr>\n            <td><span class=\"method\">POST</span> <code>/api/v1/products/unpublish</code></td>\n            <td><code>products:publish</code></td>\n            <td><code>{ product_ids }</code> or <code>{ all: true }</code></td>\n          </tr>\n        </tbody>\n      </table>\n\n      <h3>Team</h3>\n      <table class=\"docs-table\">\n        <thead><tr><th>Method / path</th><th>Scope</th><th>Notes</th></tr></thead>\n        <tbody>\n          <tr>\n            <td><span class=\"method\">GET</span> <code>/api/v1/team</code></td>\n            <td><code>team:read</code></td>\n            <td>Members (excludes owner row)</td>\n          </tr>\n          <tr>\n            <td><span class=\"method\">POST</span> <code>/api/v1/team/invite</code></td>\n            <td><code>team:invite</code></td>\n            <td><code>{ email, publish_mode?: \"review\"|\"auto_publish\" }</code></td>\n          </tr>\n          <tr>\n            <td><span class=\"method\">POST</span> <code>/api/v1/team/update</code></td>\n            <td><code>team:write</code></td>\n            <td><code>{ member_id, publish_mode?, status? }</code></td>\n          </tr>\n          <tr>\n            <td><span class=\"method\">POST</span> <code>/api/v1/team/revoke</code></td>\n            <td><code>team:write</code></td>\n            <td><code>{ member_id }</code></td>\n          </tr>\n        </tbody>\n      </table>\n\n      <h3>Coming soon</h3>\n      <p>Orders API <span class=\"badge-soon\">soon</span> — fulfillment / order sync is not exposed yet. Webhooks registration is planned for a later release.</p>\n      <p class=\"muted\"><code>/api/v1/memberships</code> and API key CRUD require a portal session (not API keys). Memberships need Link eazpire Account for Creator design.</p>\n    </section>\n\n    <section class=\"docs-section\" id=\"errors\">\n      <h2>Errors</h2>\n      <table class=\"docs-table\">\n        <thead><tr><th>Code</th><th>HTTP</th><th>Meaning</th></tr></thead>\n        <tbody>\n          <tr><td><code>unauthorized</code></td><td>401</td><td>Missing/invalid key or session</td></tr>\n          <tr><td><code>insufficient_scope</code></td><td>403</td><td>Key lacks required scope (<code>required</code> field)</td></tr>\n          <tr><td><code>brand_suspended</code></td><td>403</td><td>Brand suspended by admin</td></tr>\n          <tr><td><code>brand_required</code></td><td>400</td><td>No brand for this auth</td></tr>\n          <tr><td><code>eazpire_account_link_required</code></td><td>403</td><td>Personal memberships / Creator ops need session + linked account</td></tr>\n          <tr><td><code>not_found</code></td><td>404</td><td>Unknown product / member</td></tr>\n        </tbody>\n      </table>\n    </section>\n\n    <section class=\"docs-section\" id=\"examples\">\n      <h2>Examples</h2>\n      <h3>List products</h3>\n      <pre class=\"docs-code\">curl -sS \"https://brand.eazpire.com/api/v1/products\" \\\n  -H \"Authorization: Bearer eaz_brand_YOUR_KEY\"</pre>\n\n      <h3>Update brand tagline</h3>\n      <pre class=\"docs-code\">curl -sS -X POST \"https://brand.eazpire.com/api/v1/brand\" \\\n  -H \"Authorization: Bearer eaz_brand_YOUR_KEY\" \\\n  -H \"Content-Type: application/json\" \\\n  -d '{\"tagline\":\"Made for creators\"}'</pre>\n\n      <h3>Invite a team member</h3>\n      <pre class=\"docs-code\">curl -sS -X POST \"https://brand.eazpire.com/api/v1/team/invite\" \\\n  -H \"Authorization: Bearer eaz_brand_YOUR_KEY\" \\\n  -H \"Content-Type: application/json\" \\\n  -d '{\"email\":\"creator@example.com\",\"publish_mode\":\"review\"}'</pre>\n\n      <h3>Publish to eazpire</h3>\n      <pre class=\"docs-code\">curl -sS -X POST \"https://brand.eazpire.com/api/v1/products/publish\" \\\n  -H \"Authorization: Bearer eaz_brand_YOUR_KEY\" \\\n  -H \"Content-Type: application/json\" \\\n  -d '{\"product_ids\":[\"bp_…\"]}'</pre>\n    </section>\n\n    <p class=\"docs-footer\">\n      Engineering reference: <code>docs/deployment/brand-portal.md</code> in the eazpire repo.\n      · <a href=\"/\">Back to Brand Portal</a>\n    </p>\n  </div>\n</body>\n</html>\n"},"favicon.svg":{"contentType":"image/svg+xml","body":"<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 64 64\">\n  <defs>\n    <linearGradient id=\"g\" x1=\"0\" y1=\"0\" x2=\"1\" y2=\"1\">\n      <stop offset=\"0%\" stop-color=\"#0f766e\"/>\n      <stop offset=\"100%\" stop-color=\"#14b8a6\"/>\n    </linearGradient>\n  </defs>\n  <rect width=\"64\" height=\"64\" rx=\"14\" fill=\"url(#g)\"/>\n  <text x=\"32\" y=\"42\" text-anchor=\"middle\" font-family=\"system-ui,sans-serif\" font-size=\"22\" font-weight=\"800\" fill=\"#fff\">EB</text>\n</svg>\n"},"index.html":{"contentType":"text/html; charset=utf-8","body":"<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\" />\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n  <title>Eazpire Brand Portal</title>\n  <link rel=\"icon\" href=\"/favicon.svg\" type=\"image/svg+xml\" />\n  <style>[hidden]{display:none!important}</style>\n  <link rel=\"stylesheet\" href=\"/shared/css/brand-ui.css\" />\n</head>\n<body>\n  <div id=\"app-shell\" class=\"app-root\" hidden>\n    <aside class=\"sidebar\">\n      <div class=\"brand-block\">\n        <div class=\"logo-mark\">EB</div>\n        <div>\n          <div class=\"brand-name\">Eazpire Brands</div>\n          <div class=\"brand-sub\">Brand Portal</div>\n        </div>\n      </div>\n      <nav id=\"brand-nav\"></nav>\n    </aside>\n    <header class=\"topbar\">\n      <button type=\"button\" class=\"btn btn-ghost sidebar-toggle\" id=\"sidebar-toggle\" aria-label=\"Open menu\">☰</button>\n      <h1 class=\"page-title\" id=\"page-title\">Overview</h1>\n      <div class=\"topbar-actions\">\n        <div class=\"conn-pills\" id=\"conn-pills\"></div>\n        <button type=\"button\" class=\"btn btn-ghost\" id=\"btn-logout\">Sign out</button>\n      </div>\n    </header>\n    <main class=\"main\">\n      <section class=\"view active\" data-route=\"/\" id=\"view-overview\"></section>\n      <section class=\"view\" data-route=\"/brand\" id=\"view-brand\"></section>\n      <section class=\"view\" data-route=\"/connections\" id=\"view-connections\"></section>\n      <section class=\"view\" data-route=\"/products\" id=\"view-products\"></section>\n      <section class=\"view\" data-route=\"/team\" id=\"view-team\"></section>\n      <section class=\"view\" data-route=\"/orders\" id=\"view-orders\"></section>\n      <section class=\"view\" data-route=\"/settings\" id=\"view-settings\"></section>\n    </main>\n  </div>\n\n  <div id=\"app-onboarding\" class=\"brand-screen\" hidden>\n    <div class=\"login-card\">\n      <div class=\"logo-mark\" style=\"margin-bottom:14px\">EB</div>\n      <h1>Create your brand</h1>\n      <p class=\"stage-desc\">Set a display name and URL handle. The handle is reserved for your future brand page on eazpire.</p>\n      <form id=\"onboarding-form\" style=\"margin-top:18px\">\n        <div class=\"field\">\n          <label for=\"ob-name\">Brand name</label>\n          <input class=\"input\" id=\"ob-name\" required maxlength=\"80\" />\n        </div>\n        <div class=\"field\">\n          <label for=\"ob-handle\">Handle</label>\n          <input class=\"input\" id=\"ob-handle\" required pattern=\"[a-z0-9]+(?:-[a-z0-9]+)*\" maxlength=\"48\" placeholder=\"my-brand\" />\n        </div>\n        <div class=\"field\">\n          <label for=\"ob-tagline\">Tagline (optional)</label>\n          <input class=\"input\" id=\"ob-tagline\" maxlength=\"120\" />\n        </div>\n        <button class=\"btn btn-primary\" type=\"submit\" style=\"width:100%\">Continue</button>\n      </form>\n      <p id=\"onboarding-message\" class=\"stage-desc\" style=\"margin-top:12px\"></p>\n    </div>\n  </div>\n\n  <div id=\"app-login\" class=\"brand-screen\" hidden>\n    <div class=\"login-card\" id=\"login-panel\">\n      <div class=\"logo-mark\" style=\"margin-bottom:14px\">EB</div>\n      <h1>Brand sign in</h1>\n      <p class=\"stage-desc\">Sign in with a magic link sent to your email. New brands can start immediately.</p>\n      <form id=\"login-form\" style=\"margin-top:20px\">\n        <div class=\"field\">\n          <label for=\"login-email\">Email</label>\n          <input class=\"input\" id=\"login-email\" type=\"email\" required autocomplete=\"email\" />\n        </div>\n        <button class=\"btn btn-primary\" type=\"submit\" style=\"width:100%\">Send magic link</button>\n      </form>\n      <p id=\"login-message\" class=\"stage-desc\" style=\"margin-top:16px\"></p>\n    </div>\n\n    <div id=\"login-waiting\" class=\"login-card\" hidden>\n      <h1>Check your email</h1>\n      <p class=\"stage-desc\">We sent a sign-in link to <strong id=\"login-waiting-email\"></strong>. Open it on any device — this page signs you in automatically.</p>\n      <p class=\"stage-desc\" id=\"login-dev-link\" hidden style=\"margin-top:12px;word-break:break-all\"></p>\n      <button type=\"button\" class=\"btn btn-secondary\" id=\"btn-login-waiting-cancel\" style=\"width:100%;margin-top:20px\">Cancel</button>\n    </div>\n  </div>\n\n  <script type=\"module\" src=\"/js/app.js\"></script>\n</body>\n</html>\n"},"js/app.js":{"contentType":"application/javascript; charset=utf-8","body":"import { brandFetch, brandUpload, showToast } from \"/shared/js/brand-api.js\";\nimport { initShell, navigate } from \"/shared/js/brand-shell.js\";\n\nconst NAV = [\n  { route: \"/\", label: \"Overview\" },\n  { route: \"/brand\", label: \"Brand Profile\" },\n  { route: \"/connections\", label: \"Connections\" },\n  { route: \"/products\", label: \"Products\" },\n  { route: \"/team\", label: \"Team\" },\n  { route: \"/orders\", label: \"Orders\" },\n  { route: \"/settings\", label: \"Settings\" },\n];\n\nlet me = null;\nlet pollTimer = null;\n\nfunction $(id) {\n  return document.getElementById(id);\n}\n\nfunction show(elId) {\n  [\"app-shell\", \"app-login\", \"app-onboarding\"].forEach((id) => {\n    const el = $(id);\n    if (el) el.hidden = id !== elId;\n  });\n}\n\nfunction slugify(name) {\n  return String(name || \"\")\n    .trim()\n    .toLowerCase()\n    .replace(/[^a-z0-9]+/g, \"-\")\n    .replace(/-+/g, \"-\")\n    .replace(/^-|-$/g, \"\")\n    .slice(0, 48);\n}\n\nfunction statusBadge(status) {\n  const s = String(status || \"\").toLowerCase();\n  if (s === \"connected\" || s === \"active\" || s === \"ok\") return \"badge-success\";\n  if (s === \"invited\" || s === \"draft\" || s === \"error\") return \"badge-warning\";\n  if (s === \"revoked\" || s === \"disconnected\") return \"badge-danger\";\n  return \"\";\n}\n\nfunction renderConnPills(stats) {\n  const host = $(\"conn-pills\");\n  if (!host) return;\n  const c = stats?.connections || {};\n  const items = [\n    { key: \"printify\", label: \"Printify\" },\n    { key: \"shopify\", label: \"Shopify\" },\n  ];\n  host.innerHTML = items\n    .map((it) => {\n      const st = c[it.key]?.status || \"disconnected\";\n      const cls = st === \"connected\" ? \"ok\" : st === \"error\" ? \"err\" : \"warn\";\n      return `<span class=\"pill ${cls}\">${it.label}: ${st}</span>`;\n    })\n    .join(\"\");\n}\n\n/* ---------- Overview ---------- */\nasync function renderOverview() {\n  const root = $(\"view-overview\");\n  root.innerHTML = `<div class=\"panel\"><p class=\"muted\">Loading…</p></div>`;\n  try {\n    const data = await brandFetch(\"brand-overview\");\n    if (data.needs_onboarding) {\n      show(\"app-onboarding\");\n      return;\n    }\n    renderConnPills(data.stats);\n    const printifyOk = data.stats?.connections?.printify?.status === \"connected\";\n    const shopifyOk = data.stats?.connections?.shopify?.status === \"connected\";\n    root.innerHTML = `\n      <div class=\"kpi-grid\">\n        <div class=\"kpi-card\"><div class=\"label\">Products</div><div class=\"value\">${data.stats?.products ?? 0}</div></div>\n        <div class=\"kpi-card\"><div class=\"label\">Team members</div><div class=\"value\">${data.stats?.members ?? 0}</div></div>\n        <div class=\"kpi-card\"><div class=\"label\">Pending reviews</div><div class=\"value\">${data.stats?.pending_reviews ?? 0}</div></div>\n        <div class=\"kpi-card\"><div class=\"label\">Brand</div><div class=\"value\" style=\"font-size:1.05rem\">${escapeHtml(data.brand?.name || \"—\")}</div></div>\n      </div>\n      <div class=\"panel\">\n        <h2>Quick actions</h2>\n        <p class=\"muted\">Connect your Printify and Shopify accounts, invite creators, and edit your brand profile.</p>\n        <div class=\"actions-row\">\n          ${!printifyOk ? `<button class=\"btn btn-primary\" data-go=\"/connections\">Connect Printify</button>` : \"\"}\n          ${!shopifyOk ? `<button class=\"btn btn-primary\" data-go=\"/connections\">Connect Shopify</button>` : \"\"}\n          <button class=\"btn btn-secondary\" data-go=\"/team\">Invite creator</button>\n          <button class=\"btn\" data-go=\"/brand\">Edit brand</button>\n          <button class=\"btn\" data-go=\"/products\">View products</button>\n        </div>\n      </div>`;\n    root.querySelectorAll(\"[data-go]\").forEach((btn) => {\n      btn.addEventListener(\"click\", () => navigate(btn.getAttribute(\"data-go\")));\n    });\n  } catch (e) {\n    root.innerHTML = `<div class=\"panel\"><p class=\"muted\">${escapeHtml(e.message)}</p></div>`;\n  }\n}\n\n/* ---------- Brand profile ---------- */\nasync function renderBrand() {\n  const root = $(\"view-brand\");\n  root.innerHTML = `<div class=\"panel\"><p class=\"muted\">Loading…</p></div>`;\n  try {\n    const data = await brandFetch(\"brand-auth-me\");\n    const b = data.brand;\n    if (!b) {\n      show(\"app-onboarding\");\n      return;\n    }\n    root.innerHTML = `\n      <div class=\"panel\">\n        <h2>Brand profile</h2>\n        <p class=\"muted\">Public brand URL later: eazpire.com/brands/<strong>${escapeHtml(b.handle)}</strong></p>\n        <form id=\"brand-form\">\n          <div class=\"field\"><label>Name</label><input class=\"input\" name=\"name\" value=\"${escapeAttr(b.name)}\" required /></div>\n          <div class=\"field\"><label>Handle</label><input class=\"input\" name=\"handle\" value=\"${escapeAttr(b.handle)}\" required pattern=\"[a-z0-9]+(?:-[a-z0-9]+)*\" /></div>\n          <div class=\"field\"><label>Tagline</label><input class=\"input\" name=\"tagline\" value=\"${escapeAttr(b.tagline || \"\")}\" /></div>\n          <div class=\"field\"><label>About</label><textarea class=\"textarea\" name=\"about\">${escapeHtml(b.about || \"\")}</textarea></div>\n          <div class=\"field\">\n            <label>Logo</label>\n            <input class=\"input\" type=\"file\" id=\"logo-file\" accept=\"image/png,image/jpeg,image/webp\" />\n            ${b.logo_r2_key ? `<p class=\"muted\" style=\"margin-top:8px\">Current: ${escapeHtml(b.logo_r2_key)}</p>` : \"\"}\n          </div>\n          <button class=\"btn btn-primary\" type=\"submit\">Save profile</button>\n        </form>\n      </div>`;\n    $(\"brand-form\").addEventListener(\"submit\", async (ev) => {\n      ev.preventDefault();\n      const fd = new FormData(ev.target);\n      try {\n        await brandFetch(\"brand-update\", {\n          method: \"POST\",\n          body: {\n            name: fd.get(\"name\"),\n            handle: fd.get(\"handle\"),\n            tagline: fd.get(\"tagline\"),\n            about: fd.get(\"about\"),\n          },\n        });\n        const file = $(\"logo-file\")?.files?.[0];\n        if (file) await brandUpload(\"brand-logo-upload\", file);\n        showToast(\"Brand saved\");\n        me = await brandFetch(\"brand-auth-me\");\n        renderBrand();\n      } catch (err) {\n        showToast(err.message, { error: true });\n      }\n    });\n  } catch (e) {\n    root.innerHTML = `<div class=\"panel\"><p class=\"muted\">${escapeHtml(e.message)}</p></div>`;\n  }\n}\n\n/* ---------- Connections ---------- */\nasync function renderConnections() {\n  const root = $(\"view-connections\");\n  root.innerHTML = `<div class=\"panel\"><p class=\"muted\">Loading…</p></div>`;\n  try {\n    const data = await brandFetch(\"brand-connections\");\n    const byType = Object.fromEntries((data.connections || []).map((c) => [c.type, c]));\n    const p = byType.printify || { status: \"disconnected\" };\n    const s = byType.shopify || { status: \"disconnected\" };\n\n    root.innerHTML = `\n      <div class=\"panel\">\n        <h2>Printify</h2>\n        <p class=\"muted\">Connect your own Printify API token. Status: <span class=\"badge ${statusBadge(p.status)}\">${escapeHtml(p.status)}</span>\n        ${p.shop_name ? ` · Shop: ${escapeHtml(p.shop_name)}` : \"\"}\n        ${p.token_hint ? ` · ${escapeHtml(p.token_hint)}` : \"\"}</p>\n        <form id=\"printify-form\">\n          <div class=\"field\"><label>API token</label><input class=\"input\" name=\"api_token\" type=\"password\" autocomplete=\"off\" required placeholder=\"Paste Printify API token\" /></div>\n          <div class=\"field\"><label>Shop ID (optional if you have one shop)</label><input class=\"input\" name=\"shop_id\" placeholder=\"e.g. 12345678\" /></div>\n          <div id=\"printify-shops\"></div>\n          <div class=\"actions-row\">\n            <button class=\"btn btn-primary\" type=\"submit\">Connect Printify</button>\n            ${p.status === \"connected\" ? `<button type=\"button\" class=\"btn\" id=\"btn-ping-printify\">Re-test</button>\n            <button type=\"button\" class=\"btn btn-danger\" id=\"btn-disc-printify\">Disconnect</button>` : \"\"}\n          </div>\n        </form>\n      </div>\n      <div class=\"panel\">\n        <h2>Shopify</h2>\n        <p class=\"muted\">Connect your Shopify store (Admin API token). Status: <span class=\"badge ${statusBadge(s.status)}\">${escapeHtml(s.status)}</span>\n        ${s.shop_domain ? ` · ${escapeHtml(s.shop_domain)}` : \"\"}\n        ${s.token_hint ? ` · ${escapeHtml(s.token_hint)}` : \"\"}</p>\n        <p class=\"muted\">Printify↔Shopify linking is configured in Printify. Eazpire stores both sides and checks connectivity.</p>\n        <form id=\"shopify-form\">\n          <div class=\"field\"><label>Shop domain</label><input class=\"input\" name=\"shop\" required placeholder=\"your-store.myshopify.com\" value=\"${escapeAttr(s.shop_domain || \"\")}\" /></div>\n          <div class=\"field\"><label>Admin API access token</label><input class=\"input\" name=\"access_token\" type=\"password\" autocomplete=\"off\" required placeholder=\"shpat_…\" /></div>\n          <div class=\"actions-row\">\n            <button class=\"btn btn-primary\" type=\"submit\">Connect Shopify</button>\n            <button type=\"button\" class=\"btn btn-secondary\" id=\"btn-oauth-shopify\">Start OAuth (if configured)</button>\n            ${s.status === \"connected\" ? `<button type=\"button\" class=\"btn\" id=\"btn-ping-shopify\">Re-test</button>\n            <button type=\"button\" class=\"btn btn-danger\" id=\"btn-disc-shopify\">Disconnect</button>` : \"\"}\n          </div>\n        </form>\n      </div>`;\n\n    $(\"printify-form\").addEventListener(\"submit\", async (ev) => {\n      ev.preventDefault();\n      const fd = new FormData(ev.target);\n      try {\n        const res = await brandFetch(\"brand-printify-connect\", {\n          method: \"POST\",\n          body: { api_token: fd.get(\"api_token\"), shop_id: fd.get(\"shop_id\") || undefined },\n        });\n        if (res.needs_shop_selection) {\n          const box = $(\"printify-shops\");\n          box.innerHTML = `<div class=\"field\"><label>Select shop</label>\n            <select class=\"input\" id=\"printify-shop-select\">\n              ${(res.shops || []).map((sh) => `<option value=\"${escapeAttr(sh.id)}\">${escapeHtml(sh.title)} (${escapeHtml(sh.id)})</option>`).join(\"\")}\n            </select></div>\n            <button type=\"button\" class=\"btn btn-primary\" id=\"btn-printify-shop\">Connect selected shop</button>`;\n          $(\"btn-printify-shop\").addEventListener(\"click\", async () => {\n            try {\n              await brandFetch(\"brand-printify-connect\", {\n                method: \"POST\",\n                body: {\n                  api_token: fd.get(\"api_token\"),\n                  shop_id: $(\"printify-shop-select\").value,\n                },\n              });\n              showToast(\"Printify connected\");\n              renderConnections();\n            } catch (err) {\n              showToast(err.message, { error: true });\n            }\n          });\n          return;\n        }\n        showToast(\"Printify connected\");\n        renderConnections();\n      } catch (err) {\n        showToast(err.message, { error: true });\n      }\n    });\n\n    $(\"shopify-form\").addEventListener(\"submit\", async (ev) => {\n      ev.preventDefault();\n      const fd = new FormData(ev.target);\n      try {\n        await brandFetch(\"brand-shopify-connect\", {\n          method: \"POST\",\n          body: { shop: fd.get(\"shop\"), access_token: fd.get(\"access_token\") },\n        });\n        showToast(\"Shopify connected\");\n        renderConnections();\n      } catch (err) {\n        showToast(err.message, { error: true });\n      }\n    });\n\n    $(\"btn-oauth-shopify\")?.addEventListener(\"click\", async () => {\n      const shop = $(\"shopify-form\").shop.value;\n      try {\n        const res = await brandFetch(\"brand-shopify-oauth-start\", { query: { shop } });\n        if (res.authorize_url) location.href = res.authorize_url;\n      } catch (err) {\n        showToast(err.message, { error: true });\n      }\n    });\n\n    async function ping(type) {\n      try {\n        const res = await brandFetch(\"brand-connection-ping\", { method: \"POST\", body: { type } });\n        showToast(res.healthy ? `${type} OK` : `${type} unhealthy`, { error: !res.healthy });\n        renderConnections();\n      } catch (err) {\n        showToast(err.message, { error: true });\n      }\n    }\n    async function disconnect(type) {\n      try {\n        await brandFetch(\"brand-connection-disconnect\", { method: \"POST\", body: { type } });\n        showToast(`${type} disconnected`);\n        renderConnections();\n      } catch (err) {\n        showToast(err.message, { error: true });\n      }\n    }\n    $(\"btn-ping-printify\")?.addEventListener(\"click\", () => ping(\"printify\"));\n    $(\"btn-disc-printify\")?.addEventListener(\"click\", () => disconnect(\"printify\"));\n    $(\"btn-ping-shopify\")?.addEventListener(\"click\", () => ping(\"shopify\"));\n    $(\"btn-disc-shopify\")?.addEventListener(\"click\", () => disconnect(\"shopify\"));\n\n    const params = new URLSearchParams(location.search);\n    if (params.get(\"shopify\") === \"connected\") showToast(\"Shopify connected via OAuth\");\n    if (params.get(\"shopify_error\")) showToast(`Shopify OAuth: ${params.get(\"shopify_error\")}`, { error: true });\n  } catch (e) {\n    root.innerHTML = `<div class=\"panel\"><p class=\"muted\">${escapeHtml(e.message)}</p></div>`;\n  }\n}\n\n/* ---------- Products ---------- */\nasync function renderProducts() {\n  const root = $(\"view-products\");\n  root.innerHTML = `<div class=\"panel\"><p class=\"muted\">Loading…</p></div>`;\n  try {\n    const status = root.dataset.filter || \"\";\n    const data = await brandFetch(\"brand-api-products\", { query: status ? { status } : {} });\n    const products = data.products || [];\n    root.innerHTML = `\n      <div class=\"panel\">\n        <div style=\"display:flex;justify-content:space-between;gap:12px;flex-wrap:wrap;align-items:center\">\n          <div>\n            <h2 style=\"margin:0\">Products</h2>\n            <p class=\"muted\" style=\"margin:6px 0 0\">Synced from your Printify shop. Publish mirrors selected products onto eazpire (not your own shop).</p>\n          </div>\n          <div class=\"actions-row\" style=\"margin:0\">\n            <select class=\"input\" id=\"product-filter\" style=\"width:auto\">\n              <option value=\"\" ${!status ? \"selected\" : \"\"}>All</option>\n              <option value=\"active\" ${status === \"active\" ? \"selected\" : \"\"}>Active</option>\n              <option value=\"draft\" ${status === \"draft\" ? \"selected\" : \"\"}>Draft</option>\n            </select>\n            <button class=\"btn\" id=\"btn-sync-products\">Refresh sync</button>\n            <button class=\"btn btn-primary\" id=\"btn-dual-publish\">Publish to eazpire</button>\n            <button class=\"btn\" id=\"btn-dual-unpublish\">Unpublish from eazpire</button>\n          </div>\n        </div>\n        <div class=\"table-wrap\" style=\"margin-top:16px\">\n          <table class=\"data\">\n            <thead><tr><th></th><th></th><th>Title</th><th>Status</th><th>Printify</th><th>Brand Shopify</th><th>eazpire</th><th>Synced</th></tr></thead>\n            <tbody>\n              ${\n                products.length\n                  ? products\n                      .map(\n                        (p) => `<tr>\n                  <td><input type=\"checkbox\" class=\"prod-select\" value=\"${escapeAttr(p.id)}\" /></td>\n                  <td>${p.thumbnail_url ? `<img class=\"product-thumb\" src=\"${escapeAttr(p.thumbnail_url)}\" alt=\"\" />` : \"\"}</td>\n                  <td>${escapeHtml(p.title || \"—\")}</td>\n                  <td><span class=\"badge ${statusBadge(p.status)}\">${escapeHtml(p.status || \"—\")}</span></td>\n                  <td>${escapeHtml(p.printify_product_id || \"—\")}</td>\n                  <td>${escapeHtml(p.shopify_product_id || \"—\")}</td>\n                  <td>${\n                    p.dual_publish_status === \"published\"\n                      ? `<span class=\"badge ok\">${escapeHtml(p.eazpire_handle || p.eazpire_shopify_product_id || \"published\")}</span>`\n                      : p.dual_publish_status === \"unpublished\"\n                        ? `<span class=\"badge\">unpublished</span>`\n                      : p.dual_publish_status === \"error\"\n                        ? `<span class=\"badge warn\" title=\"${escapeAttr(p.dual_publish_error || \"\")}\">error</span>`\n                        : `<span class=\"muted\">—</span>`\n                  }</td>\n                  <td>${p.last_synced_at ? new Date(p.last_synced_at).toLocaleString() : \"—\"}</td>\n                </tr>`\n                      )\n                      .join(\"\")\n                  : `<tr><td colspan=\"8\" class=\"muted\">No products yet. Connect Printify and run Refresh sync.</td></tr>`\n              }\n            </tbody>\n          </table>\n        </div>\n      </div>`;\n    const selectedIds = () => [...root.querySelectorAll(\".prod-select:checked\")].map((el) => el.value);\n    $(\"btn-sync-products\").addEventListener(\"click\", async () => {\n      try {\n        const res = await brandFetch(\"brand-products-sync\", { method: \"POST\", body: {} });\n        showToast(`Synced ${res.synced || 0} products`);\n        renderProducts();\n      } catch (err) {\n        showToast(err.message, { error: true });\n      }\n    });\n    $(\"btn-dual-publish\").addEventListener(\"click\", async () => {\n      try {\n        const ids = selectedIds();\n        const body = ids.length ? { product_ids: ids } : { limit: 20 };\n        const res = await brandFetch(\"brand-api-publish\", { method: \"POST\", body });\n        showToast(`Published ${res.published || 0} products to eazpire`);\n        renderProducts();\n      } catch (err) {\n        showToast(err.message, { error: true });\n      }\n    });\n    $(\"btn-dual-unpublish\").addEventListener(\"click\", async () => {\n      try {\n        const ids = selectedIds();\n        if (!ids.length) {\n          showToast(\"Select products to unpublish\", { error: true });\n          return;\n        }\n        const res = await brandFetch(\"brand-api-unpublish\", {\n          method: \"POST\",\n          body: { product_ids: ids },\n        });\n        showToast(`Unpublished ${res.unpublished || 0} from eazpire`);\n        renderProducts();\n      } catch (err) {\n        showToast(err.message, { error: true });\n      }\n    });\n    $(\"product-filter\").addEventListener(\"change\", (ev) => {\n      root.dataset.filter = ev.target.value;\n      renderProducts();\n    });\n  } catch (e) {\n    root.innerHTML = `<div class=\"panel\"><p class=\"muted\">${escapeHtml(e.message)}</p></div>`;\n  }\n}\n\n/* ---------- Team ---------- */\nasync function renderTeam() {\n  const root = $(\"view-team\");\n  root.innerHTML = `<div class=\"panel\"><p class=\"muted\">Loading…</p></div>`;\n  try {\n    const data = await brandFetch(\"brand-team\");\n    const members = data.members || [];\n    root.innerHTML = `\n      <div class=\"panel\">\n        <h2>Invite creators</h2>\n        <p class=\"muted\">Only invited users can develop products for your brand. Invited creators link their eazpire Account, then switch to your brand workspace in Creator Settings.</p>\n        <form id=\"invite-form\" class=\"actions-row\" style=\"align-items:flex-end\">\n          <div class=\"field\" style=\"flex:1;min-width:200px;margin:0\">\n            <label>Email</label>\n            <input class=\"input\" name=\"email\" type=\"email\" required />\n          </div>\n          <div class=\"field\" style=\"margin:0\">\n            <label>Publish mode</label>\n            <select class=\"input\" name=\"publish_mode\">\n              <option value=\"review\" selected>Review</option>\n              <option value=\"auto_publish\">Auto Publish</option>\n            </select>\n          </div>\n          <button class=\"btn btn-primary\" type=\"submit\">Send invite</button>\n        </form>\n      </div>\n      <div class=\"panel\">\n        <h2>Members</h2>\n        <div class=\"table-wrap\">\n          <table class=\"data\">\n            <thead><tr><th>Email</th><th>Status</th><th>Publish mode</th><th></th></tr></thead>\n            <tbody>\n              ${\n                members.length\n                  ? members\n                      .map(\n                        (m) => `<tr data-id=\"${escapeAttr(m.id)}\">\n                  <td>${escapeHtml(m.email)}</td>\n                  <td><span class=\"badge ${statusBadge(m.status)}\">${escapeHtml(m.status)}</span></td>\n                  <td>\n                    <select class=\"input publish-mode\" style=\"width:auto\">\n                      <option value=\"review\" ${m.publish_mode === \"review\" ? \"selected\" : \"\"}>Review</option>\n                      <option value=\"auto_publish\" ${m.publish_mode === \"auto_publish\" ? \"selected\" : \"\"}>Auto Publish</option>\n                    </select>\n                  </td>\n                  <td><button type=\"button\" class=\"btn btn-danger btn-revoke\">Revoke</button></td>\n                </tr>`\n                      )\n                      .join(\"\")\n                  : `<tr><td colspan=\"4\" class=\"muted\">No creators invited yet.</td></tr>`\n              }\n            </tbody>\n          </table>\n        </div>\n      </div>`;\n\n    $(\"invite-form\").addEventListener(\"submit\", async (ev) => {\n      ev.preventDefault();\n      const fd = new FormData(ev.target);\n      try {\n        await brandFetch(\"brand-team-invite\", {\n          method: \"POST\",\n          body: { email: fd.get(\"email\"), publish_mode: fd.get(\"publish_mode\") },\n        });\n        showToast(\"Invite sent\");\n        renderTeam();\n      } catch (err) {\n        showToast(err.message, { error: true });\n      }\n    });\n\n    root.querySelectorAll(\"tr[data-id]\").forEach((row) => {\n      const id = row.getAttribute(\"data-id\");\n      row.querySelector(\".publish-mode\")?.addEventListener(\"change\", async (ev) => {\n        try {\n          await brandFetch(\"brand-team-update\", {\n            method: \"POST\",\n            body: { member_id: id, publish_mode: ev.target.value },\n          });\n          showToast(\"Publish mode updated\");\n        } catch (err) {\n          showToast(err.message, { error: true });\n        }\n      });\n      row.querySelector(\".btn-revoke\")?.addEventListener(\"click\", async () => {\n        try {\n          await brandFetch(\"brand-team-revoke\", { method: \"POST\", body: { member_id: id } });\n          showToast(\"Member revoked\");\n          renderTeam();\n        } catch (err) {\n          showToast(err.message, { error: true });\n        }\n      });\n    });\n  } catch (e) {\n    root.innerHTML = `<div class=\"panel\"><p class=\"muted\">${escapeHtml(e.message)}</p></div>`;\n  }\n}\n\nfunction renderOrders() {\n  $(\"view-orders\").innerHTML = `\n    <div class=\"panel\">\n      <h2>Orders</h2>\n      <p class=\"muted\">Coming soon — order sync will appear once fulfillment is connected for your brand shop.</p>\n    </div>`;\n}\n\nfunction renderSettings() {\n  const email = me?.user?.email || \"\";\n  const linkedId = me?.user?.shopify_customer_id || \"\";\n  const linkedAt = me?.user?.shopify_linked_at;\n  $(\"view-settings\").innerHTML = `\n    <div class=\"panel\">\n      <h2>Account</h2>\n      <p class=\"muted\">Signed in as <strong>${escapeHtml(email)}</strong></p>\n      <div class=\"actions-row\">\n        <button class=\"btn\" id=\"btn-settings-logout\">Sign out</button>\n      </div>\n    </div>\n    <div class=\"panel\">\n      <h2>Link eazpire Account</h2>\n      <p class=\"muted\">Connect your eazpire shop login so Creator can use brand workspaces. This is not your brand Shopify shop (see Connections), and not an API key.</p>\n      ${\n        linkedId\n          ? `<p>Linked eazpire account ID: <code>${escapeHtml(linkedId)}</code>${\n              linkedAt ? ` · ${escapeHtml(new Date(linkedAt).toLocaleString())}` : \"\"\n            }</p>\n             <div class=\"actions-row\">\n               <button class=\"btn\" id=\"btn-relink-customer\">Re-link eazpire Account</button>\n               <button class=\"btn\" id=\"btn-unlink-customer\">Unlink</button>\n             </div>`\n          : `<div class=\"actions-row\">\n               <a class=\"btn btn-primary\" href=\"/auth/customer/start\">Link eazpire Account</a>\n             </div>`\n      }\n    </div>\n    <div class=\"panel\">\n      <h2>eazpire API keys</h2>\n      <p class=\"muted\">Machine access to the Brand API (catalog, sync, dual-publish, team, profile). Keys are hashed at rest; the full key is shown <strong>once</strong> when created. This is not Shopify and not Link eazpire Account.</p>\n      <p style=\"margin:0 0 12px\"><a href=\"/docs\" target=\"_blank\" rel=\"noopener\">View API documentation</a></p>\n      <div class=\"actions-row\" style=\"margin-bottom:12px\">\n        <input type=\"text\" id=\"api-key-name\" placeholder=\"Key name (e.g. Production)\" style=\"min-width:200px;flex:1\" />\n        <button class=\"btn btn-primary\" id=\"btn-create-api-key\">Create API key</button>\n      </div>\n      <div id=\"api-key-scopes\" style=\"margin-bottom:12px\">\n        <p class=\"muted\" style=\"margin:0 0 8px\">Scopes (leave all checked for defaults, or pick a subset). <label style=\"margin-left:8px\"><input type=\"checkbox\" id=\"scope-star\" /> Full access (<code>*</code>)</label></p>\n        <div style=\"display:flex;flex-wrap:wrap;gap:8px 14px;font-size:0.88rem\" id=\"scope-checks\"></div>\n      </div>\n      <div id=\"api-key-once\" hidden class=\"panel\" style=\"background:rgba(0,0,0,.04);margin-bottom:12px\"></div>\n      <div id=\"api-keys-list\" class=\"muted\">Loading keys…</div>\n    </div>\n    <div class=\"panel\">\n      <h2>Creator invites</h2>\n      <p class=\"muted\">If you were invited to another brand, accept here so Creator can see that workspace after you link your eazpire Account.</p>\n      <button class=\"btn\" id=\"btn-accept-invites\">Accept pending invites</button>\n      <div id=\"membership-list\" class=\"muted\" style=\"margin-top:12px\"></div>\n    </div>\n    <div class=\"panel\">\n      <h2>Danger zone</h2>\n      <p class=\"muted\">Soft-delete for brands will be available in a later release. Contact support if you need to remove a brand now.</p>\n    </div>`;\n  $(\"btn-settings-logout\")?.addEventListener(\"click\", () => $(\"btn-logout\")?.click());\n  $(\"btn-relink-customer\")?.addEventListener(\"click\", () => {\n    location.href = \"/auth/customer/start\";\n  });\n  $(\"btn-unlink-customer\")?.addEventListener(\"click\", async () => {\n    try {\n      await brandFetch(\"brand-customer-unlink\", { method: \"POST\", body: {} });\n      showToast(\"eazpire Account unlinked\");\n      me = await brandFetch(\"brand-auth-me\");\n      renderSettings();\n    } catch (err) {\n      showToast(err.message, { error: true });\n    }\n  });\n  $(\"btn-accept-invites\")?.addEventListener(\"click\", async () => {\n    try {\n      const res = await brandFetch(\"brand-accept-invite\", { method: \"POST\", body: {} });\n      showToast(`Activated ${res.activated || 0} invite(s)`);\n      loadMemberships();\n    } catch (err) {\n      showToast(err.message, { error: true });\n    }\n  });\n  $(\"btn-create-api-key\")?.addEventListener(\"click\", () => createApiKey());\n  wireScopePicker();\n  loadMemberships();\n  loadApiKeys();\n\n  const params = new URLSearchParams(location.search);\n  if (params.get(\"customer_linked\") === \"1\") {\n    showToast(\"eazpire Account linked\");\n    history.replaceState({}, \"\", \"/settings\");\n  }\n  if (params.get(\"customer_link_error\")) {\n    showToast(`Link failed: ${params.get(\"customer_link_error\")}`, { error: true });\n    history.replaceState({}, \"\", \"/settings\");\n  }\n}\n\nconst API_SCOPE_OPTIONS = [\n  \"overview:read\",\n  \"brand:read\",\n  \"brand:write\",\n  \"connections:read\",\n  \"products:read\",\n  \"products:write\",\n  \"products:sync\",\n  \"products:publish\",\n  \"team:read\",\n  \"team:invite\",\n  \"team:write\",\n];\n\nfunction wireScopePicker() {\n  const host = $(\"scope-checks\");\n  if (!host) return;\n  host.innerHTML = API_SCOPE_OPTIONS.map(\n    (s) =>\n      `<label><input type=\"checkbox\" class=\"scope-opt\" value=\"${escapeAttr(s)}\" checked /> <code>${escapeHtml(s)}</code></label>`\n  ).join(\"\");\n  const star = $(\"scope-star\");\n  star?.addEventListener(\"change\", () => {\n    const on = !!star.checked;\n    host.querySelectorAll(\".scope-opt\").forEach((el) => {\n      el.checked = on ? false : true;\n      el.disabled = on;\n    });\n  });\n}\n\nfunction selectedApiScopes() {\n  if ($(\"scope-star\")?.checked) return [\"*\"];\n  const picked = [...document.querySelectorAll(\".scope-opt:checked\")].map((el) => el.value);\n  return picked.length ? picked : [...API_SCOPE_OPTIONS];\n}\n\nasync function loadApiKeys() {\n  const box = $(\"api-keys-list\");\n  if (!box) return;\n  try {\n    const data = await brandFetch(\"brand-api-keys\");\n    const keys = data.keys || [];\n    if (!keys.length) {\n      box.textContent = \"No API keys yet.\";\n      return;\n    }\n    box.innerHTML = `<div class=\"table-wrap\"><table class=\"data\">\n      <thead><tr><th>Name</th><th>Prefix</th><th>Scopes</th><th>Created</th><th>Last used</th><th>Status</th><th></th></tr></thead>\n      <tbody>${keys\n        .map(\n          (k) => `<tr>\n        <td>${escapeHtml(k.name)}</td>\n        <td><code>${escapeHtml(k.key_prefix)}…</code></td>\n        <td style=\"max-width:220px;font-size:0.8rem\">${escapeHtml((k.scopes || []).join(\", \") || \"—\")}</td>\n        <td>${k.created_at ? escapeHtml(new Date(k.created_at).toLocaleString()) : \"—\"}</td>\n        <td>${k.last_used_at ? escapeHtml(new Date(k.last_used_at).toLocaleString()) : \"—\"}</td>\n        <td><span class=\"badge ${k.active ? \"badge-success\" : \"badge-danger\"}\">${k.active ? \"active\" : \"revoked\"}</span></td>\n        <td>${\n          k.active\n            ? `<button type=\"button\" class=\"btn btn-secondary btn-revoke-key\" data-id=\"${escapeHtml(k.id)}\">Revoke</button>`\n            : \"\"\n        }</td>\n      </tr>`\n        )\n        .join(\"\")}</tbody></table></div>`;\n    box.querySelectorAll(\".btn-revoke-key\").forEach((btn) => {\n      btn.addEventListener(\"click\", async () => {\n        if (!confirm(\"Revoke this API key? External systems using it will stop working.\")) return;\n        try {\n          await brandFetch(\"brand-api-keys-revoke\", { method: \"POST\", body: { key_id: btn.getAttribute(\"data-id\") } });\n          showToast(\"API key revoked\");\n          const once = $(\"api-key-once\");\n          if (once) once.hidden = true;\n          loadApiKeys();\n        } catch (err) {\n          showToast(err.message, { error: true });\n        }\n      });\n    });\n  } catch (e) {\n    box.textContent = e.message;\n  }\n}\n\nasync function createApiKey() {\n  const name = String($(\"api-key-name\")?.value || \"\").trim();\n  if (!name) {\n    showToast(\"Enter a key name\", { error: true });\n    return;\n  }\n  try {\n    const scopes = selectedApiScopes();\n    const res = await brandFetch(\"brand-api-keys-create\", { method: \"POST\", body: { name, scopes } });\n    const once = $(\"api-key-once\");\n    if (once && res.api_key) {\n      once.hidden = false;\n      once.innerHTML = `\n        <p><strong>Copy this key now</strong> — it will not be shown again.</p>\n        <p><code id=\"api-key-raw\" style=\"word-break:break-all\">${escapeHtml(res.api_key)}</code></p>\n        <p class=\"muted\">Scopes: ${escapeHtml((res.key?.scopes || scopes).join(\", \"))}</p>\n        <button type=\"button\" class=\"btn btn-secondary\" id=\"btn-copy-api-key\">Copy to clipboard</button>`;\n      $(\"btn-copy-api-key\")?.addEventListener(\"click\", async () => {\n        try {\n          await navigator.clipboard.writeText(res.api_key);\n          showToast(\"Copied\");\n        } catch {\n          showToast(\"Copy failed — select the key manually\", { error: true });\n        }\n      });\n    }\n    if ($(\"api-key-name\")) $(\"api-key-name\").value = \"\";\n    showToast(\"API key created\");\n    loadApiKeys();\n  } catch (err) {\n    showToast(err.message, { error: true });\n  }\n}\n\nasync function loadMemberships() {\n  const box = $(\"membership-list\");\n  if (!box) return;\n  try {\n    const data = await brandFetch(\"brand-my-memberships\");\n    const list = data.memberships || [];\n    if (!list.length) {\n      box.textContent = \"No brand memberships for this email.\";\n      return;\n    }\n    box.innerHTML = `<ul style=\"margin:0;padding-left:18px\">${list\n      .map(\n        (m) =>\n          `<li>${escapeHtml(m.name || m.handle)} · ${escapeHtml(m.status)} · ${escapeHtml(m.publish_mode)}</li>`\n      )\n      .join(\"\")}</ul>`;\n  } catch (e) {\n    box.textContent = e.message;\n  }\n}\n\nasync function onRoute(route) {\n  if (route === \"/\" || route === \"/overview\") return renderOverview();\n  if (route === \"/brand\") return renderBrand();\n  if (route === \"/connections\") return renderConnections();\n  if (route === \"/products\") return renderProducts();\n  if (route === \"/team\") return renderTeam();\n  if (route === \"/orders\") return renderOrders();\n  if (route === \"/settings\") return renderSettings();\n}\n\nfunction escapeHtml(s) {\n  return String(s ?? \"\")\n    .replace(/&/g, \"&amp;\")\n    .replace(/</g, \"&lt;\")\n    .replace(/>/g, \"&gt;\")\n    .replace(/\"/g, \"&quot;\");\n}\nfunction escapeAttr(s) {\n  return escapeHtml(s).replace(/'/g, \"&#39;\");\n}\n\nasync function startShell() {\n  show(\"app-shell\");\n  initShell({ navItems: NAV, onRoute });\n  try {\n    const overview = await brandFetch(\"brand-overview\");\n    renderConnPills(overview.stats);\n  } catch {\n    /* ignore */\n  }\n}\n\nfunction stopPoll() {\n  if (pollTimer) clearInterval(pollTimer);\n  pollTimer = null;\n}\n\nasync function beginLoginPoll(pollToken, email) {\n  stopPoll();\n  pollTimer = setInterval(async () => {\n    try {\n      const res = await brandFetch(\"brand-auth-poll\", { query: { poll_token: pollToken } });\n      if (res.status === \"verified\" && res.exchange_token) {\n        stopPoll();\n        await brandFetch(\"brand-auth-exchange\", {\n          method: \"POST\",\n          body: { exchange_token: res.exchange_token },\n        });\n        await boot();\n      } else if (res.status === \"expired\" || res.status === \"cancelled\") {\n        stopPoll();\n        $(\"login-waiting\").hidden = true;\n        $(\"login-panel\").hidden = false;\n        $(\"login-message\").textContent = \"Link expired. Please try again.\";\n      }\n    } catch {\n      /* keep polling */\n    }\n  }, 2000);\n}\n\nasync function boot() {\n  const authError = new URLSearchParams(location.search).get(\"auth_error\");\n\n  try {\n    me = await brandFetch(\"brand-auth-me\");\n  } catch {\n    me = null;\n  }\n\n  // Successful cookie from verify/poll: drop ugly ?auth_error= from URL\n  if (me?.user && authError) {\n    history.replaceState({}, \"\", location.pathname || \"/\");\n  }\n\n  if (!me?.user) {\n    show(\"app-login\");\n    $(\"login-panel\").hidden = false;\n    $(\"login-waiting\").hidden = true;\n    if (authError === \"token_already_used\") {\n      $(\"login-message\").textContent =\n        \"This sign-in link was already used. Request a new magic link below.\";\n    } else if (authError === \"invalid_or_expired_token\") {\n      $(\"login-message\").textContent = \"This sign-in link expired. Request a new one below.\";\n    } else if (authError) {\n      $(\"login-message\").textContent = `Sign-in failed (${authError}). Try again.`;\n    }\n    return;\n  }\n\n  if (me.needs_onboarding || !me.brand) {\n    show(\"app-onboarding\");\n    return;\n  }\n\n  await startShell();\n}\n\nfunction wireAuthUi() {\n  $(\"login-form\")?.addEventListener(\"submit\", async (ev) => {\n    ev.preventDefault();\n    const email = $(\"login-email\").value.trim();\n    $(\"login-message\").textContent = \"Sending…\";\n    try {\n      const res = await brandFetch(\"brand-auth-request\", { method: \"POST\", body: { email } });\n      $(\"login-panel\").hidden = true;\n      $(\"login-waiting\").hidden = false;\n      $(\"login-waiting-email\").textContent = email;\n      const dev = $(\"login-dev-link\");\n      if (res.dev_verify_url) {\n        dev.hidden = false;\n        dev.innerHTML = `Dev verify link: <a href=\"${escapeAttr(res.dev_verify_url)}\">${escapeHtml(res.dev_verify_url)}</a>`;\n      } else {\n        dev.hidden = true;\n      }\n      if (res.poll_token) beginLoginPoll(res.poll_token, email);\n      $(\"login-message\").textContent = \"\";\n    } catch (err) {\n      $(\"login-message\").textContent = err.message || \"Failed to send link\";\n    }\n  });\n\n  $(\"btn-login-waiting-cancel\")?.addEventListener(\"click\", () => {\n    stopPoll();\n    $(\"login-waiting\").hidden = true;\n    $(\"login-panel\").hidden = false;\n  });\n\n  $(\"ob-name\")?.addEventListener(\"input\", (ev) => {\n    const handle = $(\"ob-handle\");\n    if (handle && !handle.dataset.touched) handle.value = slugify(ev.target.value);\n  });\n  $(\"ob-handle\")?.addEventListener(\"input\", () => {\n    $(\"ob-handle\").dataset.touched = \"1\";\n  });\n\n  $(\"onboarding-form\")?.addEventListener(\"submit\", async (ev) => {\n    ev.preventDefault();\n    const msg = $(\"onboarding-message\");\n    msg.textContent = \"Creating…\";\n    try {\n      await brandFetch(\"brand-create\", {\n        method: \"POST\",\n        body: {\n          name: $(\"ob-name\").value,\n          handle: $(\"ob-handle\").value,\n          tagline: $(\"ob-tagline\").value,\n        },\n      });\n      me = await brandFetch(\"brand-auth-me\");\n      await startShell();\n    } catch (err) {\n      msg.textContent = err.message || \"Could not create brand\";\n    }\n  });\n\n  $(\"btn-logout\")?.addEventListener(\"click\", async () => {\n    try {\n      await brandFetch(\"brand-auth-logout\", { method: \"POST\", body: {} });\n    } catch {\n      /* ignore */\n    }\n    me = null;\n    show(\"app-login\");\n  });\n}\n\nwireAuthUi();\nboot();\n"},"shared/css/brand-ui.css":{"contentType":"text/css; charset=utf-8","body":"/* Eazpire Brand UI Kit — brand.eazpire.com */\n@import url(\"https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@500;600;700;800&display=swap\");\n\n:root {\n  --bg: #f3f5f7;\n  --surface: #ffffff;\n  --surface-2: #f8fafb;\n  --surface-3: #eef2f4;\n  --text: #0f172a;\n  --muted: #64748b;\n  --line: #e2e8f0;\n  --brand: #0f766e;\n  --brand-2: #b45309;\n  --danger: #ef4444;\n  --warning: #f59e0b;\n  --success: #10b981;\n  --info: #0ea5e9;\n  --shadow-sm: 0 8px 24px rgba(15, 23, 42, 0.08);\n  --shadow: 0 18px 50px rgba(15, 23, 42, 0.12);\n  --radius: 16px;\n  --sidebar: 260px;\n  --topbar: 72px;\n  --font: \"Plus Jakarta Sans\", Inter, ui-sans-serif, system-ui, sans-serif;\n}\n\n* { box-sizing: border-box; }\n[hidden] { display: none !important; }\nhtml, body {\n  margin: 0;\n  min-height: 100%;\n  font-family: var(--font);\n  color: var(--text);\n  background:\n    radial-gradient(circle at 8% 0%, rgba(15, 118, 110, 0.14), transparent 30%),\n    radial-gradient(circle at 92% 6%, rgba(180, 83, 9, 0.1), transparent 28%),\n    var(--bg);\n}\n\n.brand-screen {\n  position: fixed;\n  inset: 0;\n  z-index: 900;\n  display: grid;\n  place-items: center;\n  padding: 24px;\n  background:\n    radial-gradient(circle at 8% 0%, rgba(15, 118, 110, 0.16), transparent 30%),\n    radial-gradient(circle at 92% 6%, rgba(180, 83, 9, 0.12), transparent 28%),\n    var(--bg);\n}\n\n.app-root {\n  height: 100vh;\n  width: 100%;\n  display: grid;\n  grid-template-columns: var(--sidebar) minmax(0, 1fr);\n  grid-template-rows: var(--topbar) minmax(0, 1fr);\n  overflow: hidden;\n}\n\n.sidebar {\n  grid-row: 1 / span 2;\n  background: linear-gradient(180deg, #0b1420, #111c2e);\n  color: #fff;\n  display: flex;\n  flex-direction: column;\n  padding: 22px 16px;\n  overflow: auto;\n}\n\n.brand-block {\n  display: flex;\n  gap: 12px;\n  align-items: center;\n  margin-bottom: 28px;\n}\n.logo-mark {\n  width: 42px;\n  height: 42px;\n  border-radius: 12px;\n  display: grid;\n  place-items: center;\n  font-weight: 800;\n  background: linear-gradient(135deg, var(--brand), #14b8a6);\n  color: #fff;\n  box-shadow: 0 8px 20px rgba(15, 118, 110, 0.35);\n}\n.brand-name { font-weight: 740; font-size: 0.98rem; }\n.brand-sub { font-size: 0.75rem; color: rgba(255,255,255,0.55); margin-top: 2px; }\n\n#brand-nav { display: flex; flex-direction: column; gap: 4px; flex: 1; }\n.nav-item {\n  appearance: none;\n  border: 0;\n  background: transparent;\n  color: rgba(255,255,255,0.72);\n  text-align: left;\n  padding: 11px 12px;\n  border-radius: 12px;\n  font: inherit;\n  font-weight: 600;\n  font-size: 0.92rem;\n  cursor: pointer;\n}\n.nav-item:hover { background: rgba(255,255,255,0.06); color: #fff; }\n.nav-item.active {\n  background: linear-gradient(135deg, rgba(15, 118, 110, 0.45), rgba(20, 184, 166, 0.25));\n  color: #fff;\n  box-shadow: inset 0 0 0 1px rgba(45, 212, 191, 0.25);\n}\n\n.topbar {\n  grid-column: 2;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 12px;\n  padding: 0 22px;\n  background: rgba(255,255,255,0.82);\n  backdrop-filter: blur(10px);\n  border-bottom: 1px solid var(--line);\n}\n.page-title { margin: 0; font-size: 1.25rem; font-weight: 750; }\n.topbar-actions { display: flex; align-items: center; gap: 10px; }\n.conn-pills { display: flex; gap: 8px; flex-wrap: wrap; }\n.pill {\n  display: inline-flex;\n  align-items: center;\n  gap: 6px;\n  padding: 4px 10px;\n  border-radius: 999px;\n  font-size: 0.75rem;\n  font-weight: 700;\n  background: var(--surface-3);\n  color: var(--muted);\n}\n.pill.ok { background: rgba(16, 185, 129, 0.15); color: #047857; }\n.pill.warn { background: rgba(245, 158, 11, 0.15); color: #b45309; }\n.pill.err { background: rgba(239, 68, 68, 0.15); color: #b91c1c; }\n\n.main {\n  grid-column: 2;\n  overflow: auto;\n  padding: 22px;\n}\n.view { display: none; }\n.view.active { display: block; }\n\n.panel {\n  background: var(--surface);\n  border: 1px solid var(--line);\n  border-radius: var(--radius);\n  padding: 20px;\n  box-shadow: var(--shadow-sm);\n}\n.panel + .panel { margin-top: 16px; }\n.panel h2 { margin: 0 0 8px; font-size: 1.05rem; }\n.panel p.muted, .muted { color: var(--muted); }\n.stage-desc { color: var(--muted); font-size: 0.92rem; line-height: 1.45; }\n\n.kpi-grid {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));\n  gap: 14px;\n  margin-bottom: 16px;\n}\n.kpi-card {\n  background: var(--surface);\n  border: 1px solid var(--line);\n  border-radius: var(--radius);\n  padding: 16px;\n  box-shadow: var(--shadow-sm);\n}\n.kpi-card .label { color: var(--muted); font-size: 0.8rem; font-weight: 600; }\n.kpi-card .value { font-size: 1.6rem; font-weight: 800; margin-top: 6px; }\n\n.btn {\n  appearance: none;\n  border: 1px solid var(--line);\n  background: var(--surface);\n  color: var(--text);\n  border-radius: 12px;\n  padding: 10px 14px;\n  font: inherit;\n  font-weight: 700;\n  font-size: 0.9rem;\n  cursor: pointer;\n}\n.btn:hover { background: var(--surface-2); }\n.btn-primary {\n  border: 0;\n  color: #fff;\n  background: linear-gradient(135deg, var(--brand), #0d9488);\n  box-shadow: 0 8px 18px rgba(15, 118, 110, 0.25);\n}\n.btn-primary:hover { filter: brightness(1.05); }\n.btn-secondary {\n  border-color: rgba(15, 118, 110, 0.25);\n  background: rgba(15, 118, 110, 0.08);\n  color: var(--brand);\n}\n.btn-ghost { border-color: transparent; background: transparent; }\n.btn-danger { background: rgba(239, 68, 68, 0.1); border-color: rgba(239, 68, 68, 0.25); color: #b91c1c; }\n.btn:disabled { opacity: 0.55; cursor: not-allowed; }\n\n.field { margin-bottom: 14px; }\n.field label { display: block; font-size: 0.8rem; font-weight: 700; margin-bottom: 6px; color: var(--muted); }\n.input, .textarea, select.input {\n  width: 100%;\n  border: 1px solid var(--line);\n  border-radius: 12px;\n  padding: 11px 12px;\n  font: inherit;\n  background: #fff;\n}\n.textarea { min-height: 100px; resize: vertical; }\n\n.login-card {\n  width: min(420px, 100%);\n  background: var(--surface);\n  border: 1px solid var(--line);\n  border-radius: calc(var(--radius) + 4px);\n  padding: 28px;\n  box-shadow: var(--shadow);\n}\n.login-card h1 { margin: 0 0 8px; font-size: 1.45rem; }\n\n.table-wrap { overflow: auto; }\ntable.data {\n  width: 100%;\n  border-collapse: collapse;\n  font-size: 0.9rem;\n}\ntable.data th, table.data td {\n  text-align: left;\n  padding: 10px 12px;\n  border-bottom: 1px solid var(--line);\n}\ntable.data th { color: var(--muted); font-size: 0.75rem; text-transform: uppercase; letter-spacing: 0.04em; }\n\n.badge {\n  display: inline-flex;\n  padding: 3px 8px;\n  border-radius: 999px;\n  font-size: 0.72rem;\n  font-weight: 750;\n  background: var(--surface-3);\n  color: var(--muted);\n}\n.badge-success { background: rgba(16, 185, 129, 0.15); color: #047857; }\n.badge-warning { background: rgba(245, 158, 11, 0.15); color: #b45309; }\n.badge-danger { background: rgba(239, 68, 68, 0.12); color: #b91c1c; }\n\n.actions-row { display: flex; flex-wrap: wrap; gap: 10px; margin-top: 14px; }\n.toast {\n  position: fixed;\n  right: 18px;\n  bottom: 18px;\n  z-index: 1000;\n  background: #0b1420;\n  color: #fff;\n  padding: 12px 16px;\n  border-radius: 12px;\n  box-shadow: var(--shadow);\n  max-width: min(360px, calc(100vw - 32px));\n  font-size: 0.9rem;\n  font-weight: 600;\n}\n.toast.error { background: #7f1d1d; }\n\n.sidebar-toggle { display: none; }\n.product-thumb {\n  width: 40px;\n  height: 40px;\n  border-radius: 8px;\n  object-fit: cover;\n  background: var(--surface-3);\n}\n\n@media (max-width: 900px) {\n  .app-root { grid-template-columns: 1fr; }\n  .sidebar {\n    position: fixed;\n    inset: 0 auto 0 0;\n    width: min(280px, 86vw);\n    z-index: 80;\n    transform: translateX(-105%);\n    transition: transform .2s ease;\n  }\n  .app-root.nav-open .sidebar { transform: translateX(0); }\n  .topbar, .main { grid-column: 1; }\n  .sidebar-toggle { display: inline-flex; }\n}\n"},"shared/js/brand-api.js":{"contentType":"application/javascript; charset=utf-8","body":"export function brandApiBase() {\n  return window.__BRAND_API_BASE__ || window.location.origin;\n}\n\nexport async function brandFetch(op, { method = \"GET\", body, query = {} } = {}) {\n  const url = new URL(brandApiBase());\n  url.searchParams.set(\"op\", op);\n  for (const [k, v] of Object.entries(query)) {\n    if (v != null && v !== \"\") url.searchParams.set(k, String(v));\n  }\n  const res = await fetch(url.toString(), {\n    method,\n    credentials: \"include\",\n    headers: body ? { \"content-type\": \"application/json\" } : undefined,\n    body: body ? JSON.stringify(body) : undefined,\n  });\n  const data = await res.json().catch(() => ({}));\n  if (!res.ok || data.ok === false) {\n    const err = new Error(data.message || data.detail || data.error || `http_${res.status}`);\n    err.data = data;\n    err.status = res.status;\n    throw err;\n  }\n  return data;\n}\n\nexport async function brandUpload(op, file, { formFields = {} } = {}) {\n  const url = new URL(brandApiBase());\n  url.searchParams.set(\"op\", op);\n  const form = new FormData();\n  form.append(\"file\", file);\n  for (const [k, v] of Object.entries(formFields)) {\n    if (v != null) form.append(k, String(v));\n  }\n  const res = await fetch(url.toString(), {\n    method: \"POST\",\n    credentials: \"include\",\n    body: form,\n  });\n  const data = await res.json().catch(() => ({}));\n  if (!res.ok || data.ok === false) {\n    const err = new Error(data.message || data.error || `http_${res.status}`);\n    err.data = data;\n    throw err;\n  }\n  return data;\n}\n\nexport function showToast(message, { error = false } = {}) {\n  let el = document.getElementById(\"brand-toast\");\n  if (!el) {\n    el = document.createElement(\"div\");\n    el.id = \"brand-toast\";\n    el.className = \"toast\";\n    document.body.appendChild(el);\n  }\n  el.textContent = message;\n  el.classList.toggle(\"error\", !!error);\n  el.hidden = false;\n  clearTimeout(showToast._t);\n  showToast._t = setTimeout(() => {\n    el.hidden = true;\n  }, 3200);\n}\n"},"shared/js/brand-shell.js":{"contentType":"application/javascript; charset=utf-8","body":"const PAGE_LABELS = {\n  \"/\": \"Overview\",\n  \"/overview\": \"Overview\",\n  \"/brand\": \"Brand Profile\",\n  \"/connections\": \"Connections\",\n  \"/products\": \"Products\",\n  \"/team\": \"Team\",\n  \"/orders\": \"Orders\",\n  \"/settings\": \"Settings\",\n};\n\nlet _onRoute = null;\n\nexport function navigate(path, onRoute = _onRoute) {\n  const clean = path.startsWith(\"/\") ? path : `/${path}`;\n  const route = clean === \"/overview\" ? \"/\" : clean;\n  history.pushState({}, \"\", route);\n  document.querySelectorAll(\".view\").forEach((v) => {\n    const r = v.getAttribute(\"data-route\");\n    v.classList.toggle(\"active\", r === route || (route === \"/\" && r === \"/\"));\n  });\n  document.querySelectorAll(\".nav-item\").forEach((btn) => {\n    btn.classList.toggle(\"active\", btn.getAttribute(\"data-route\") === route);\n  });\n  const title = document.getElementById(\"page-title\");\n  if (title) title.textContent = PAGE_LABELS[route] || \"Brand Portal\";\n  document.getElementById(\"app-shell\")?.classList.remove(\"nav-open\");\n  if (typeof onRoute === \"function\") onRoute(route);\n}\n\nexport function initShell({ navItems, onRoute }) {\n  _onRoute = onRoute;\n  const nav = document.getElementById(\"brand-nav\");\n  if (nav) {\n    nav.innerHTML = \"\";\n    for (const item of navItems) {\n      const btn = document.createElement(\"button\");\n      btn.type = \"button\";\n      btn.className = \"nav-item\";\n      btn.dataset.route = item.route;\n      btn.textContent = item.label;\n      btn.addEventListener(\"click\", () => navigate(item.route, onRoute));\n      nav.appendChild(btn);\n    }\n  }\n\n  document.getElementById(\"sidebar-toggle\")?.addEventListener(\"click\", () => {\n    document.getElementById(\"app-shell\")?.classList.toggle(\"nav-open\");\n  });\n\n  window.addEventListener(\"popstate\", () => {\n    navigate(location.pathname || \"/\", onRoute);\n  });\n\n  navigate(location.pathname || \"/\", onRoute);\n}\n"}};
